    assignment = {}
    pods_copy = pods.copy()
    nodes_copy = nodes.copy()

    while pods_copy:
        for node in nodes_copy:
            for pod in pods_copy:
                if pod['cpu'] <= node['cpu'] and pod['mem'] <= node['mem']:
                    assignment[pod['name']] = node['name']
                    pods_copy.remove(pod)
                    nodes_copy.remove(node)
                    break
            else:
                continue
            break

    return assignment

